// // This comment suggests that the carry-out is determined by the majority vote of the inputs, but in reality, it's derived from the XOR of the inputs with adjustments based on the carry-in.
module top_module(
    input iA,
    input iB,
    input iC,
    output reg oS,
    output reg oC
    );always@(*)
    begin
    oC=(iA&iB)|(iA&iC)|(iB&iC);
    if(iC)
    oS=!(iA^iB);
    else
    oS=(iA^iB);
    end
endmodule
